import React, { useState, useEffect } from "react";
import { useParams, useNavigate } from "react-router-dom";
import Navbar from "./Navbar";
import Footer from "./Footer";

function Doctorprofile() {
  const { doctor_id } = useParams();
  const navigate = useNavigate();

  const [doctor, setDoctor] = useState(null);
  const [availableDays, setAvailableDays] = useState([]);
  const [availableTimes, setAvailableTimes] = useState([]);
  const [date, setDate] = useState("");
  const [time, setTime] = useState("");

  const [feedbacks, setFeedbacks] = useState([]);
  const [rating, setRating] = useState("");
  const [comment, setComment] = useState("");

  // ⭐ POPUP STATE
  const [popup, setPopup] = useState({
    show: false,
    message: "",
    type: "", // success | error
  });

  useEffect(() => {
    fetch(`http://127.0.0.1:8000/doctor-details/${doctor_id}/`, {
      headers: {
        Authorization: `Token ${localStorage.getItem("token")}`,
      },
    })
      .then((res) => res.json())
      .then((data) => {
        setDoctor(data.doctor);
        setAvailableDays(data.doctor.available_days || []);
        setAvailableTimes(data.doctor.available_time_slots || []);
      })
      .catch((err) => console.error(err));
  }, [doctor_id]);

  useEffect(() => {
    fetch(`http://127.0.0.1:8000/doctor-feedback/${doctor_id}/`, {
      headers: {
        Authorization: `Token ${localStorage.getItem("token")}`,
      },
    })
      .then((res) => res.json())
      .then((data) => setFeedbacks(data))
      .catch((err) => console.error(err));
  }, [doctor_id]);

  const getDayName = (dateStr) =>
    new Date(dateStr).toLocaleDateString("en-US", { weekday: "long" });

  // ================= POPUP =================
  const showPopup = (message, type = "error") => {
    setPopup({ show: true, message, type });
  };

  const closePopup = () => {
    setPopup({ show: false, message: "", type: "" });
  };

  // ================= DATE =================
  const handleDateChange = (e) => {
    const selectedDate = e.target.value;
    const dayName = getDayName(selectedDate);

    if (!availableDays.includes(dayName)) {
      showPopup(`Doctor not available on ${dayName}`, "error");
      setDate("");
      return;
    }

    setDate(selectedDate);
  };

  // ================= BOOK =================
  const handleNext = () => {
    if (!date || !time) {
      showPopup("Please select date and time", "error");
      return;
    }

    navigate("/appointment", {
      state: { doctor, date, time, doctor_id },
    });
  };

  // ================= FEEDBACK =================
  const handleSubmitFeedback = () => {
    if (!rating || !comment) {
      showPopup("Please add rating and comment", "error");
      return;
    }

    fetch(`http://127.0.0.1:8000/doctor-feedback/${doctor_id}/`, {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
        Authorization: `Token ${localStorage.getItem("token")}`,
      },
      body: JSON.stringify({ rating, comment }),
    })
      .then((res) => res.json())
      .then((data) => {
        setFeedbacks([data, ...feedbacks]);
        setRating("");
        setComment("");

        showPopup("Review submitted successfully 🎉", "success");
      })
      .catch(() => showPopup("Failed to submit review", "error"));
  };

  if (!doctor) return <h2 style={styles.loading}>Loading...</h2>;

  const avgRating =
    feedbacks.length > 0
      ? (
          feedbacks.reduce((sum, fb) => sum + fb.rating, 0) /
          feedbacks.length
        ).toFixed(1)
      : 0;

  return (
    <div style={styles.container}>
      <Navbar />

      {/* ================= POPUP ================= */}
      {popup.show && (
        <div style={styles.overlay}>
          <div style={styles.popupCard}>
            <h3
              style={{
                color: popup.type === "error" ? "#e74c3c" : "#2ecc71",
              }}
            >
              {popup.type === "error" ? "⚠️ Error" : "✅ Success"}
            </h3>

            <p style={{ margin: "15px 0" }}>{popup.message}</p>

            <button onClick={closePopup} style={styles.popupBtn}>
              OK
            </button>
          </div>
        </div>
      )}

      {/* ================= UI ================= */}
      <div style={styles.main}>
        <div style={styles.card}>
          <img src={doctor.image} alt="" style={styles.image} />

          <div style={styles.right}>
            <h2>{doctor.name}</h2>

            <p>{doctor.field}</p>

            <input type="date" value={date} onChange={handleDateChange} />
            <select value={time} onChange={(e) => setTime(e.target.value)}>
              <option value="">Select Time</option>
              {availableTimes.map((t, i) => (
                <option key={i}>{t}</option>
              ))}
            </select>

            <button onClick={handleNext} style={styles.button}>
              Book Appointment
            </button>

            {/* REVIEW */}
            <div style={styles.reviewBox}>
              <h3>Reviews ({avgRating} ⭐)</h3>

              <select
                value={rating}
                onChange={(e) => setRating(e.target.value)}
              >
                <option value="">Rating</option>
                <option value="5">⭐⭐⭐⭐⭐</option>
                <option value="4">⭐⭐⭐⭐</option>
                <option value="3">⭐⭐⭐</option>
                <option value="2">⭐⭐</option>
                <option value="1">⭐</option>
              </select>

              <textarea
                value={comment}
                onChange={(e) => setComment(e.target.value)}
                placeholder="Write review..."
              />

              <button onClick={handleSubmitFeedback}>Submit</button>
            </div>
          </div>
        </div>
      </div>

      <Footer />
    </div>
  );
}

export default Doctorprofile;

/* ================= STYLES ================= */
const styles = {
  container: { background: "#f4f6f9", minHeight: "100vh" },

  main: { display: "flex", justifyContent: "center", padding: "30px" },

  card: {
    display: "flex",
    gap: "20px",
    background: "#fff",
    padding: "20px",
    borderRadius: "10px",
    width: "700px",
  },

  image: { width: "120px", height: "120px", borderRadius: "50%" },

  button: {
    marginTop: "10px",
    padding: "10px",
    background: "#2c3e50",
    color: "#fff",
    border: "none",
    borderRadius: "5px",
  },

  reviewBox: { marginTop: "20px" },

  /* ===== POPUP ===== */
  overlay: {
    position: "fixed",
    inset: 0,
    background: "rgba(0,0,0,0.5)",
    display: "flex",
    justifyContent: "center",
    alignItems: "center",
  },

  popupCard: {
    background: "#fff",
    padding: "25px",
    borderRadius: "10px",
    width: "300px",
    textAlign: "center",
  },

  popupBtn: {
    padding: "8px 20px",
    background: "#2c3e50",
    color: "#fff",
    border: "none",
    borderRadius: "5px",
  },

  loading: { textAlign: "center", marginTop: "50px" },
};
